@st.cache_data
def load_data():
    with open("iceberg_dataset_clean.json", "r", encoding="utf-8") as f:
        data = json.load(f)
    df = pd.DataFrame(data)
    def norm(series):
        mn, mx = series.min(), series.max()
        if mx == mn: return pd.Series(np.zeros(len(series)), index=series.index)
        return (series - mn) / (mx - mn)
    df["score_reindustrialisation"] = (norm(df["surface_km2"])*.25 + norm(1/df["prix_m2_moy"].replace(0,np.nan).fillna(df["prix_m2_moy"].median()))*.25 + norm(df["taux_chomage"])*.25 + norm(df["nb_gares_stations"])*.15 + norm(df["nb_etab_formation"])*.10)
    df["score_employabilite"] = (norm(df["taux_chomage"])*.30 + norm(df["nb_etab_formation"])*.25 + norm(df["nb_entreprises"])*.20 + norm(df["nb_gares_stations"])*.15 + norm(df["densite_pop_km2"])*.10)
    df["score_attractivite"] = norm(df["score_reindustrialisation"]*.50 + df["score_employabilite"]*.50)
    df["score_signal_faible"] = norm(norm(df["taux_pauvrete_commune"])*.30 + norm(df["variation_chomage"].clip(lower=0))*.25 + norm(1/df["entreprises_1000hab"].replace(0,np.nan).fillna(1))*.25 + norm(1/df["revenu_median"].replace(0,np.nan).fillna(df["revenu_median"].median()))*.20)
    df["score_desert_medical"] = norm(norm(df["population"])*.35 + norm(1/df["nb_etab_formation"].replace(0,np.nan).fillna(.5))*.35 + norm(df["taux_pauvrete_commune"])*.20 + norm(df["densite_pop_km2"])*.10)
    df["score_desert_commercial"] = norm(norm(df["population"])*.40 + norm(1/df["entreprises_1000hab"].replace(0,np.nan).fillna(1))*.35 + norm(df["taux_pauvrete_commune"])*.25)
    df["score_desert_mobilite"] = norm(norm(df["population"])*.50 + norm(1/df["nb_gares_stations"].replace(0,np.nan).fillna(.5))*.50)
    for col in ["score_attractivite","score_signal_faible","score_desert_medical","score_desert_commercial","score_desert_mobilite","score_reindustrialisation","score_employabilite"]:
        df[col] = df[col].fillna(0)
    df["cat_attractivite"] = df["score_attractivite"].apply(lambda s: "Zone Prioritaire" if s>=.70 else ("Zone Favorable" if s>=.50 else ("Zone Possible" if s>=.30 else "Non Recommandé")))
    df["cat_signal_faible"] = df["score_signal_faible"].apply(lambda s: "Signal Fort" if s>=.65 else ("Signal Modéré" if s>=.40 else "Signal Faible"))
    for col2 in ["cat_desert_medical","cat_desert_commercial","cat_desert_mobilite"]:
        sc = col2.replace("cat_","score_")
        df[col2] = df[sc].apply(lambda s: "Fort" if s>=.65 else ("Modéré" if s>=.40 else "Faible"))
    return df
df = load_data()

def safe_val(val, decimals=0):
    try:
        v = float(val)
        if np.isnan(v): return "N/A"
        if decimals == 0: return f"{int(v):,}".replace(",", " ")
        return round(v, decimals)
    except: return 'N/A'

ville_names = sorted(df['ville'].dropna().unique().tolist())

def get_data_summary():
    t_attr = df.nlargest(5,"score_attractivite")[["ville","score_attractivite","cat_attractivite"]].to_dict("records")
    t_med  = df.nlargest(5,"score_desert_medical")[["ville","score_desert_medical","cat_desert_medical"]].to_dict("records")
    t_sig  = df.nlargest(5,"score_signal_faible")[["ville","score_signal_faible","cat_signal_faible"]].to_dict("records")
    return f"""Tu es un expert en intelligence territoriale (Essonne 91, Val-de-Marne 94, 241 communes).
Top attractivité: {t_attr}. Top déserts médicaux: {t_med}. Top signaux faibles: {t_sig}.
Zones prioritaires: {len(df[df["cat_attractivite"]=="Zone Prioritaire"])}. Déserts méd forts: {len(df[df["cat_desert_medical"]=="Fort"])}.
Réponds en français, de façon concise et professionnelle."""

